"use client";
import SplitText from "gsap/src/SplitText";
import ScrollTrigger from "gsap/src/ScrollTrigger";
import { useGSAP } from "@gsap/react";
import gsap from "gsap";
import { useRef } from "react";

gsap.registerPlugin(SplitText, ScrollTrigger);

const TextAssemble = () => {
  const containerRef = useRef<HTMLDivElement>(null);

  useGSAP(
    () => {
      const split = new SplitText(".st", { type: "chars" });

      const scrollTween = gsap.to(".con", {
        xPercent: -100,
        ease: "none",
        scrollTrigger: {
          trigger: ".wrapper",
          pin: true,
          scrub: true,
          end: () => "+=10000px",
        },
      });

      split.chars.forEach((char) => {
        gsap.from(char, {
          x: gsap.utils.random(0, 500),
          y: gsap.utils.random(-200, 200),
          rotate: gsap.utils.random(-20, 20),
          scrollTrigger: {
            containerAnimation: scrollTween,
            trigger: char,
            start: "left 100%",
            end: "left 80%",
            scrub: 1,
          },
        });
      });
    },
    { scope: containerRef }
  );

  return (
    <div ref={containerRef}>
      <div className=" h-screen "></div>
      <div className="wrapper h-screen flex items-center">
        <div className="con px-4">
          <span className="st text-xs text-nowrap ">
            LIKE έΑλ FOLLOW έΑλ STAY TUNED έεο Building cool things every day έεο
            Sharing what actually works έεο From bugs έΗΤ breakthroughs έεο Design έΑλ
            Code έΑλ Ship έΑλ Repeat έαΖ DonέΑβt just watch έΑΦ build with me έαΖ έαΗ Real
            projects. Real progress. No noise. έεπ ΆΧν έε▒ έεπ έεο έετ έευ έεφ έεχ έεψ έε░ έαΖ έαΗ έε╡ έε╢ έε╖ έε╕
            έε╣ έε║ έε╗ έε╝ έε╜ έε╛ έε┐ έεπ ΆΧν FOLLOW FOR: έΗΤ clean UI ideas έΗΤ dev experiments έΗΤ
            behin
          </span>
        </div>
      </div>
      <div className="wrapper h-screen flex items-center bg-red-200"></div>
    </div>
  );
};

export default TextAssemble;
